    fn certificate_peer_id_matches_public_key() {
        // Generate a new identity keypair and corresponding certificate
        let keypair = identity::Keypair::generate_ed25519();
        let (cert_der, _cert_key) = generate(&keypair).unwrap();
        // Parse the certificate and extract peer_id
        let p2p_cert = parse(&cert_der).unwrap();
        let peer_id_from_cert = p2p_cert.peer_id();
        // Directly compute peer_id from the public key
        let peer_id_direct = keypair.public().to_peer_id();
        assert_eq!(peer_id_from_cert, peer_id_direct);
    }
}

