// Tests for Config.message_id behavior
use libp2p_gossipsub::{ConfigBuilder};
use libp2p_gossipsub::types::{Message, MessageId};
use libp2p_gossipsub::topic::TopicHash;

#[test]
fn custom_message_id_fn() {
    // Build config with custom message_id function
    let cfg = ConfigBuilder::default()
        .message_id_fn(|_| MessageId::new(b"test_id"))
        .build()
        .expect("should build config");
    // Create a dummy message
    let msg = Message {
        source: None,
        data: Vec::new(),
        sequence_number: None,
        topic: TopicHash::from_raw(""),
    };
    // message_id should delegate to custom function
    assert_eq!(cfg.message_id(&msg), MessageId::new(b"test_id"));
}

// Tests for RSA sign and verify
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_sign_and_verify_success() {
        // Load a PKCS#8 private key
        let mut der = include_bytes!("test/rsa-2048.pk8").to_vec();
        let keypair = Keypair::try_decode_pkcs8(&mut der).expect("Failed to decode private key");
        let public = keypair.public();
        let msg = b"hello world";
        let sig = keypair.sign(msg).expect("Failed to sign message");
        assert!(public.verify(msg, &sig));
    }

    #[test]
    fn test_verify_with_modified_message_fails() {
        let mut der = include_bytes!("test/rsa-2048.pk8").to_vec();
        let keypair = Keypair::try_decode_pkcs8(&mut der).expect("Failed to decode private key");
        let public = keypair.public();
        let msg = b"hello world";
        let sig = keypair.sign(msg).expect("Failed to sign message");
        // Different message should fail verification
        assert!(!public.verify(b"goodbye world", &sig));
    }

    #[test]
    fn test_verify_with_modified_signature_fails() {
        let mut der = include_bytes!("test/rsa-2048.pk8").to_vec();
        let keypair = Keypair::try_decode_pkcs8(&mut der).expect("Failed to decode private key");
        let public = keypair.public();
        let msg = b"hello world";
        let mut sig = keypair.sign(msg).expect("Failed to sign message");
        // Corrupt the signature
        sig[0] ^= 0xFF;
        assert!(!public.verify(msg, &sig));
    }
}
